### Task 9: Update `flush_hnsw()` for 5 files
**File:** `crates/corvia-kernel/src/lite_store.rs` (lines 632-653)
**What:**
1. For each MemoryType, dump to `{type}.hnsw.{graph,data}`
2. Remove old per-type dump files before writing
3. Persist next_hnsw_id once (global counter)

```rust
pub fn flush_hnsw(&self) -> Result<()> {
    let hnsw_dir = self.data_dir.join("hnsw");
    std::fs::create_dir_all(&hnsw_dir)?;

    for (mt, hnsw_arc) in &self.hnsw_indexes {
        let basename = hnsw_basename(*mt);
        let _ = std::fs::remove_file(hnsw_dir.join(format!("{basename}.hnsw.graph")));
        let _ = std::fs::remove_file(hnsw_dir.join(format!("{basename}.hnsw.data")));
        let hnsw = hnsw_arc.load_full();
        hnsw.file_dump(&hnsw_dir, basename)
            .map_err(|e| CorviaError::Storage(format!("Failed to dump {basename} HNSW: {e}")))?;
    }

    self.persist_next_id()?;
    info!("HNSW flushed ({} indexes) to {}", self.hnsw_indexes.len(), hnsw_dir.display());
    Ok(())
}
```


